

import { HeroSection }   from './HeroSection'
import { FilterSidebar } from './components/FilterSidebar'
import { JobSections }   from './components/JobSections'

export default function JobsPage() {
  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: '#f7f3ef' }}>

      {/* ── LEFT  — sticky hero ─────────────────────────────────────── */}
      <aside style={{
        width: '42%',
        maxWidth: '560px',
        flexShrink: 0,
        position: 'sticky',
        top: 0,
        height: '100vh',
        overflowY: 'auto',
      }}>
        <HeroSection />
      </aside>

      {/* ── RIGHT — scrollable job content ──────────────────────────── */}
      <main style={{
        flex: 1,
        minWidth: 0,
        overflowY: 'auto',
        padding: '32px 32px 64px',
        display: 'flex',
        flexDirection: 'column',
        gap: '24px',
      }}>
        <FilterSidebar />
        <JobSections />
      </main>

    </div>
  )
}